#[test]
fn all_three_datasets_summarized() {
    // Cross-domain smoke test: print a single summary table.
    let results = [
        run(Dataset::InvoiceNet).expect("InvoiceNet"),
        run(Dataset::CzechBank).expect("CzechBank"),
        run(Dataset::AdultIncome).expect("AdultIncome"),
    ];
    println!();
    println!("=== THEMIS 3.0 cross-domain bench (C-15 / AC15) ===");
    println!(
        "{:<14} {:>6} {:>6} {:>6} {:>6} {:>8} {:>8} {:>6}",
        "Dataset", "rows", "TP", "FP", "FN", "recall", "target", "FPR"
    );
    for r in &results {
        let target = recall_target(r.dataset);
        let pass = if r.recall >= target { "PASS" } else { "FAIL" };
        println!(
            "{:<14} {:>6} {:>6} {:>6} {:>6} {:>8.3} {:>8.3} {:>6.3} {}",
            r.dataset.name(),
            r.rows,
            r.tp,
            r.fp,
            r.fn_,
            r.recall,
            target,
            r.fpr,
            pass
        );
    }
    println!("===================================================");
    for r in &results {
        assert_meets(r);
    }
}
